)

Rules.InvariantScript:
Set(gblTextClickedSaveScreen, "Jobs Screen");
Navigate(
    'Saving Screen',
    ScreenTransition.Fade,
    {locSaveText: "Refreshing data from Vesta Data..."}
)

// Open Vesta Measure (new) app
Launch(LookUp(colCdsVestaSettings, Key="Vesta Measure (Legacy) App URL", Value));
UpdateContext({locShowSwitchApp: false});

With(
    {
        varRows: CountRows(
            Filter(
                colCdsJobEntries,
                colCdsJobEntries[@Job].Job = gblRecordJobSpotlight.Job
            )
        )
    },
    Concatenate(
        Coalesce(
            Text(varRows),
            "0"
        ),
        If(
            varRows = 1,
            " Measure",
            " Measures"
        )
    )
)

Set(
    gblRecordJobCurrent,
    gblRecordJobSpotlight
);
If(
    gblRecordJobCurrent.'Is Source Vesta Deal?'<>gblOptionSets.Job.IsSourceVestaDeal.Yes,
    UpdateContext({locShowSwitchApp: true}),
    Navigate(
        'Job Details Screen',
        ScreenTransition.Fade,
        {
            locReOpenClosedJobDecisionMade: false,
            locCurrentJobDetailsPage: 1
        }
    )
);

// get the job record
Set(
    gblRecordJobCurrent,
    ThisItem
);
If(
    gblRecordJobCurrent.'Is Source Vesta Deal?'<>gblOptionSets.Job.IsSourceVestaDeal.Yes,
    UpdateContext({locShowSwitchApp: true}),
    IsToday(gblRecordJobCurrent.'Start Date Time') Or gblRecordJobCurrent.Job in colAUDRecords.RecordRef,
    Navigate(
        'Job Details Screen',
        ScreenTransition.Fade,
        {locReOpenClosedJobDecisionMade: false, locCurrentJobDetailsPage:1}
    ),
    Navigate(
        'Load Job Screen',
        ScreenTransition.Fade
    )
)
